const formatDate = (dmy: string): string => {
    const parts = dmy.split('/');
    if (parts.length !== 3) {
        console.warn(`Invalid date format found: ${dmy}`);
        return new Date().toISOString().split('T')[0];
    }
    const day = parts[0].padStart(2, '0');
    const month = parts[1].padStart(2, '0');
    const year = parts[2];
    // Assuming year 2020 for all entries based on data
    return `${year}-${month}-${day}`;
};

export const getLegacyRepairs = (): Repair[] => {
    const groupedByDateAndPlate: Record<string, Repair> = {};

    rawLegacyData.forEach((item, index) => {
        // Skip items with nonsensical prices or quantities
        if (item.unitPrice <= 0 || item.quantity <= 0) {
            return;
        }

        const formattedDate = formatDate(item.purchaseDate);
        const key = `${formattedDate}-${item.licensePlate}`;

        const part: PartRequisitionItem = {
            partId: `legacy-${index}`,
            name: item.partName,
            code: item.requisitionNumber || item.invoice || '',
            quantity: item.quantity,
            unit: item.unit,
            unitPrice: item.unitPrice,
            source: 'ร้านค้า',
            supplierName: item.supplier,
            purchaseDate: formattedDate,
        };

        if (!groupedByDateAndPlate[key]) {
             const dateForISO = `${formattedDate}T09:00:00.000Z`;
             groupedByDateAndPlate[key] = {
                id: `LEGACY-${key}`,
                repairOrderNo: `LEGACY-${formattedDate.replace(/-/g, '')}-${Object.keys(groupedByDateAndPlate).length}`,
                requisitionNumber: item.requisitionNumber,
                invoiceNumber: item.invoice,
                licensePlate: item.licensePlate,
                vehicleType: item.vehicleType,
                vehicleMake: item.make || '',
                vehicleModel: item.model || '',
                currentMileage: 'N/A',
                reportedBy: 'ระบบเก่า',
                repairCategory: 'ซ่อมบำรุงตามประวัติ',
                problemDescription: 'ซ่อมบำรุงตามประวัติและเปลี่ยนอะไหล่ตามรายการ',
                priority: 'ปกติ',
                status: 'ซ่อมเสร็จ',
                createdAt: dateForISO,
                updatedAt: dateForISO,
                approvalDate: undefined,
                assignedTechnician: '',
                repairStartDate: dateForISO,
                repairEndDate: dateForISO,
                dispatchType: 'ภายใน',
                repairCost: 0,
                partsVat: 0,
                parts: [part],
                attachments: [],
            };
        } else {
            groupedByDateAndPlate[key].parts.push(part);
            if (item.requisitionNumber && !groupedByDateAndPlate[key].requisitionNumber?.includes(item.requisitionNumber)) {
                groupedByDateAndPlate[key].requisitionNumber += `, ${item.requisitionNumber}`;
            }
             if (item.invoice && !groupedByDateAndPlate[key].invoiceNumber?.includes(item.invoice)) {
                groupedByDateAndPlate[key].invoiceNumber += `, ${item.invoice}`;
            }
        }
    });

    return Object.values(groupedByDateAndPlate);
};